+            raw: {
+              incr: jest.fn().mockImplementation((key: string) => {
+                counters[key] = (counters[key] ?? 0) + 1;
+                return counters[key];
+              }),
+              expire: jest.fn().mockResolvedValue(1)
+            }
+          }
+        },
+        {
+          provide: RateLimitService,
+          useValue: {
+            getPerUserLimit: jest.fn().mockResolvedValue(60)
+          }
