    allowedHeaders: ["Content-Type", "x-csrf-token"],
    optionsSuccessStatus: 204
  });

  app.use(helmet());
  app.use(cookieParser());
  app.setGlobalPrefix("api");
  app.enableVersioning({
    type: VersioningType.URI,
    prefix: "v"
  });
  app.useGlobalPipes(
