    expect(createSpy).not.toHaveBeenCalledWith(
      expect.objectContaining({
        data: expect.objectContaining({
          channel: "prepaid_balance",
          idempotencyKey
        })
      })
    );
  });

  it("rejects replayed nonce and stale timestamp", async () => {
